package com.assetflow.nexora.entity;
import jakarta.persistence.*; import java.time.*; @Entity @Table(name="resource_bookings") public class ResourceBooking extends AuditedEntity { @Id @GeneratedValue(strategy=GenerationType.IDENTITY) @Column(name="booking_id") public Long id; @Column(name="asset_id",nullable=false) public Long assetId; @Column(name="booked_by",nullable=false) public Long bookedBy; @Column(name="department_id") public Long departmentId; @Column(length=255) public String purpose; @Column(name="start_time",nullable=false) public OffsetDateTime startTime; @Column(name="end_time",nullable=false) public OffsetDateTime endTime; @Column(nullable=false,length=20) public String status="Upcoming"; @Column(name="cancelled_by") public Long cancelledBy; @Column(name="cancelled_at") public OffsetDateTime cancelledAt; }
